(b) => {
  const serverUrl = String(b.getValue('serverUrl') || '');
  const token = String(b.getValue('token') || '');
  const number = String(b.getValue('number') || '');
  const text = b.getValue('text');
  const target = String(b.getValue('target') || 'messageResult');
  return `const ${target} = await (async () => {
  try {
    const response = await fetch('${serverUrl}/send/text', {
      method: 'POST',
      headers: {
        'Accept': 'application/json',
        'Content-Type': 'application/json',
        'token': '${token}'
      },
      body: JSON.stringify({
        number: '${number}',
        text: ${text}
      })
    });
    const data = await response.json();
    if(window.__addLog) window.__addLog('WhatsApp message sent to ' + '${number}', 'info');
    return data;
  } catch(e) {
    if(window.__addLog) window.__addLog('Error: ' + e.message, 'error');
    return { error: e.message };
  }
})();`;
}

(b) => {
