  const mediaUrl = b.getValue('mediaUrl');
  const caption = b.getValue('caption');
  const target = String(b.getValue('target') || 'mediaResult');
  const endpoints = {
    'image': 'send/image',
    'video': 'send/video',
    'audio': 'send/audio',
    'document': 'send/document'
  };
  const endpoint = endpoints[mediaType] || 'send/image';
  return `const ${target} = await (async () => {
  try {
    const response = await fetch('${serverUrl}/${endpoint}', {
      method: 'POST',
      headers: {
        'Accept': 'application/json',
        'Content-Type': 'application/json',
        'token': '${token}'
      },
      body: JSON.stringify({
        number: '${number}',
        url: ${mediaUrl},
        caption: ${caption ? String(caption) : 'null'}
      })
    });
    const data = await response.json();
    if(window.__addLog) window.__addLog('WhatsApp media sent to ' + '${number}', 'info');
    return data;
  } catch(e) {
    if(window.__addLog) window.__addLog('Error: ' + e.message, 'error');
    return { error: e.message };
  }
})();`;
}

